/**
 * Extracts relevant headers from an HTTP request and converts them into gRPC metadata.
 * Forwards standard proxy headers, custom headers with the x-custom- prefix,
 * and any explicitly listed headers.
 *
 * @param {http.IncomingMessage} httpRequest - The incoming HTTP request
 * @param {string[]} additionalHeaders - Additional header names to forward
 * @returns {grpc.Metadata} gRPC metadata populated with forwarded headers
 */
function httpHeadersToGrpcMetadata(httpRequest, additionalHeaders = []) {
  const metadata = new grpc.Metadata();
  const headers = httpRequest.headers;

  // Combine standard forwarded headers with any additional ones
  const headersToForward = new Set([
    ...FORWARDED_HEADERS,
    ...additionalHeaders.map((h) => h.toLowerCase()),
  ]);

  // Forward explicitly listed headers
  for (const headerName of headersToForward) {
    const value = headers[headerName];
    if (value !== undefined && value !== null) {
      if (Array.isArray(value)) {
        value.forEach((v) => metadata.add(headerName, v));
      } else {
        metadata.add(headerName, String(value));
      }
    }
  }

  // Forward all custom headers with the x-custom- prefix
  for (const [key, value] of Object.entries(headers)) {
    const lowerKey = key.toLowerCase();
    if (lowerKey.startsWith(CUSTOM_HEADER_PREFIX) && !headersToForward.has(lowerKey)) {
      if (Array.isArray(value)) {
        value.forEach((v) => metadata.add(lowerKey, v));
      } else {
        metadata.add(lowerKey, String(value));
      }
    }
  }

  // Add gateway-specific metadata
  metadata.add('x-gateway-timestamp', new Date().toISOString());
  metadata.add('x-original-method', httpRequest.method || 'UNKNOWN');
  metadata.add('x-original-path', httpRequest.url || '/');

  // Extract and forward client IP
  const clientIp =
    headers['x-forwarded-for'] ||
    headers['x-real-ip'] ||
    httpRequest.socket.remoteAddress;
  if (clientIp && !metadata.get('x-forwarded-for').length) {
    metadata.add('x-forwarded-for', String(clientIp));
  }

  return metadata;
}

/**
 * Makes a unary gRPC call with forwarded HTTP headers.
 *
 * @param {grpc.Client} client - The gRPC client instance
 * @param {string} methodName - The gRPC method to call
 * @param {Object} requestBody - The request payload
 * @param {grpc.Metadata} metadata - The gRPC metadata with forwarded headers
 * @returns {Promise<Object>} The gRPC response
 */
function makeGrpcCall(client, methodName, requestBody, metadata) {
  return new Promise((resolve, reject) => {
    if (typeof client[methodName] !== 'function') {
      return reject(new Error(`Method "${methodName}" not found on gRPC client`));
    }

    client[methodName](requestBody, metadata, (error, response) => {
      if (error) {
        reject(error);
      } else {
        resolve(response);
      }
    });
  });
}

/**
 * Makes a server-streaming gRPC call with forwarded HTTP headers.
 *
 * @param {grpc.Client} client - The gRPC client instance
 * @param {string} methodName - The gRPC method to call
 * @param {Object} requestBody - The request payload
 * @param {grpc.Metadata} metadata - The gRPC metadata with forwarded headers
 * @returns {Promise<Object[]>} Array of streamed responses
 */
function makeGrpcServerStreamCall(client, methodName, requestBody, metadata) {
  return new Promise((resolve, reject) => {
    if (typeof client[methodName] !== 'function') {
      return reject(new Error(`Method "${methodName}" not found on gRPC client`));
    }

    const responses = [];
    const call = client[methodName](requestBody, metadata);

    call.on('data', (data) => {
      responses.push(data);
    });

    call.on('error', (error) => {
      reject(error);
    });

    call.on('end', () => {
      resolve(responses);
    });
  });
}

/**
 * Parses the HTTP request body as JSON.
 *
 * @param {http.IncomingMessage} req - The HTTP request
 * @returns {Promise<Object>} Parsed JSON body
 */
function parseRequestBody(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', (chunk) => {
      body += chunk.toString();
    });
    req.on('end', () => {
      try {
        resolve(body ? JSON.parse(body) : {});
      } catch (e) {
        reject(new Error('Invalid JSON body'));
      }
    });
    req.on('error', reject);
  });
}

/**
 * Maps gRPC error codes to HTTP status codes.
 *
 * @param {number} grpcCode - The gRPC status code
 * @returns {number} Corresponding HTTP status code
 */
function grpcCodeToHttpStatus(grpcCode) {
  const mapping = {
    [grpc.status.OK]: 200,
    [grpc.status.CANCELLED]: 499,
    [grpc.status.UNKNOWN]: 500,
    [grpc.status.INVALID_ARGUMENT]: 400,
    [grpc.status.DEADLINE_EXCEEDED]: 504,
    [grpc.status.NOT_FOUND]: 404,
    [grpc.status.ALREADY_EXISTS]: 409,
    [grpc.status.PERMISSION_DENIED]: 403,
    [grpc.status.UNAUTHENTICATED]: 401,
    [grpc.status.RESOURCE_EXHAUSTED]: 429,
    [grpc.status.FAILED_PRECONDITION]: 412,
    [grpc.status.ABORTED]: 409,
    [grpc.status.OUT_OF_RANGE]: 400,
    [grpc.status.UNIMPLEMENTED]: 501,
    [grpc.status.INTERNAL]: 500,
    [grpc.status.UNAVAILABLE]: 503,
    [grpc.status.DATA_LOSS]: 500,
  };
  return mapping[grpcCode] || 500;
}

